sp_widget.css:
.sp-search-heading {
	color: #ffffee !important; 
  font-size: 65px;

  text-shadow:     0 1px 0 hsl(174,5%,80%),
	                 0 2px 0 hsl(174,5%,75%),
	                 0 3px 0 hsl(174,5%,70%),
	                 0 4px 0 hsl(174,5%,66%),

	                 0 0 5px rgba(0,0,0,.05),
	                0 1px 3px rgba(0,0,0,.2),
	                0 3px 5px rgba(0,0,0,.2),
	               0 5px 10px rgba(0,0,0,.2),
	              0 10px 10px rgba(0,0,0,.2);
}

.short-description{
	font-size: 45px;
  padding: 0px;
}
.sp-tagline-color {
	color: $sp-tagline-color;
}

@media (forced-colors: active) {
  .sp-search-heading {
    background-color: Canvas;
  }
}

#homepage-search {
  min-height: 450px;
  display: flex;
  align-items: center;

  .aisearch {
    --classicsponlydonotuse--rem-multipy: 1.6;
  }
  .aisearch-container {
	  height: 36px;
  }

}

sp_widget.link:
function link() {
      var geckoRegex = /Gecko\/\d+/; // Remove forced-colors css for Gecko engine (Firefox) as they already handle it
      if (geckoRegex.test(navigator.userAgent)) {
        $('.sp-search-heading').removeClass('sp-search-heading');
      }
}

sp_widget.script:
data.userName = gs.getUser().getFirstName();

var aisEnabled = $sp.isAISearchEnabled();

if (aisEnabled) {
    options['utterancePlacement'] = 'body';
    options['placement'] = 'dynamic-landing';
	data.typeAheadSearch = $sp.getWidget('toy-typeahead-search', options);
} else
	data.typeAheadSearch = $sp.getWidget('toy-typeahead-search', options.typeahead_search);
